Materialize the base join rows BEFORE the correlated collection projections so app/AppStatus/chkAppStatus are built client-side (mirrors EF6's implicit client evaluation, output-preserving). Replace the single `var v = (from a in db.PackingLists ... let app=... let AppStatus=... let chkAppStatus=... where ... select new {...}).ToList().Select(o => new {...})` with a two-stage query:

Stage 1 â€” server-side base rows only (no correlated collections in the projection):
var baseRows = (from a in db.PackingLists
    join b in db.Customers on a.Customer equals b.CustomerID into payfrom
    from b in payfrom.DefaultIfEmpty()
    join g in db.Users on a.CreatedBy equals g.Id
    where ((InvoiceNo == null || InvoiceNo == "" || a.BillNo == InvoiceNo) &&
           (FromDate == null || FromDate == "" || EF.Functions.DateDiffDay(a.PLDate, fdate) <= 0) &&
           (ToDate == null || ToDate == "" || EF.Functions.DateDiffDay(a.PLDate, tdate) >= 0)) &&
          (user == null || user == "" || g.Id == user) &&
          (Customer == null || Customer == 0 || a.Customer == Customer) &&
          (LPO == null || LPO == "" || a.LPO == LPO)
    select new {
        a.PackinglistId, Invoice = a.BillNo, LPO = a.LPO, Date = a.PLDate,
        Customer = b.CustomerName, CreatedBy = g.Name, Billno = a.BillNo,
        Status = a.Status, a.CreatedDate
    }).ToList();   // <-- materialization boundary moved BEFORE the correlated collections

Stage 2 â€” build the per-row collections client-side (these now run as independent queries / in-memory, exactly like Common.cs does safely), then the final Select:
var v = baseRows.Select(o => {
        var app = db.Approvals.Where(x => x.TransEntry == o.PackinglistId && x.Type == "PackingList").Select(x => x.EmployeeId).ToList();
        var AppStatus = db.ApprovalUpdates.Where(x => x.TransEntry == o.PackinglistId && x.Type == "PackingList").Select(x => x.ApprovalStatus).ToList();
        var chkAppStatus = db.ApprovalUpdates.Where(x => x.TransEntry == o.PackinglistId && x.Type == "PackingList")
                             .AsEnumerable()                       // force client-side before the GroupBy top-1-entity
                             .GroupBy(l => l.ApprovedBy)
                             .Select(grp => grp.OrderByDescending(c => c.CreatedDate).FirstOrDefault())
                             .Select(x => x.ApprovalStatus).ToList();
        return new {
            o.PackinglistId, o.Invoice, o.LPO, o.Date, o.Customer, o.CreatedBy, o.Billno, o.Status,
            Dev = uDev, Edit = uEdit, Delete = uDelete, app = app,
            Approval = (app != null && empl.EmployeeId != null) ? app.Contains(empl.EmployeeId) : false,
            ApprovalStatus = (app.Count > 0 && AppStatus.Count > 0 && chkAppStatus.Count > 0)
